    		 import sailpoint.api.*;
         import sailpoint.object.*;
         import java.util.Date;
         import java.text.DateFormat;
         import java.text.SimpleDateFormat;	
         import sailpoint.tools.Util;
         import java.text.DateFormat;

                       if(identity != null){
           	boolean inactive = identity.isInactive();
            String hireDate = identity.getAttribute("hireDate");
            String primaryEmail = identity.getAttribute("primaryEmail");
            
            if( Util.isNotNullOrEmpty(hireDate) && Util.isNotNullOrEmpty(primaryEmail) && !inactive){
              
               int daysDiff;
               double hireDaysDiff = 0;
               SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
               Date dateNow = sdf.parse(sdf.format(new Date()));
               Date hireDt = sdf.parse(hireDate);
               
               if(null != dateNow && null != hireDt){			        
                  hireDaysDiff = (((dateNow.getTime() - hireDt.getTime()))/ (1000 * 60 * 60 * 24));
                   daysDiff = (int)hireDaysDiff;              
                  if((daysDiff <= 30) && (daysDiff >= 0)){
                     return true;
                  }
               }
            }
         }
         return false;
